use fastly::http::{Method, StatusCode};
use fastly::{Backend, Error, Request, Response};

fn make_backend(
    name: &str,
    host: &str,
    port: u16,
    sni_hostname: &str,
    use_ssl: bool,
) -> Result<Backend, Error> {
    let target = format!("{}:{}", host, port);

    let mut builder = Backend::builder(name, target.as_str());
    builder = builder.override_host(host);

    if use_ssl {
        builder = builder.enable_ssl();
        builder = builder.set_sni_hostname(sni_hostname);
        builder = builder.check_certificate(true);
        builder = builder.min_tls_version(fastly::tls::TlsVersion::TLS1_2);
        builder = builder.max_tls_version(fastly::tls::TlsVersion::TLS1_3);
    }

    builder.finish()
}

fn select_backend(req: &Request) -> Result<Backend, Error> {
    match req.get_path() {
        p if p.starts_with("/api/") => {
            make_backend("api_backend", "api.example.com", 443, "api.example.com", true)
        }
        p if p.starts_with("/static/") => make_backend(
            "static_backend",
            "static.example.com",
            443,
            "static.example.com",
            true,
        ),
        _ => make_backend("app_backend", "app.example.com", 8443, "app.example.com", true),
    }
}

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    if req.get_method() == Method::OPTIONS {
        return Ok(
            Response::from_status(StatusCode::NO_CONTENT)
                .with_header("access-control-allow-origin", "*")
                .with_header(
                    "access-control-allow-methods",
                    "GET, HEAD, POST, PUT, PATCH, DELETE, OPTIONS",
                )
                .with_header("access-control-allow-headers", "*")
                .with_header("access-control-max-age", "86400"),
        );
    }

    let backend = select_backend(&req)?;

    req.set_header("x-forwarded-host", req.get_header_str("host").unwrap_or_default());

    let mut bereq = req;
    bereq.set_pass(true);

    let mut beresp = bereq.send(backend)?;

    beresp.set_header("x-routed-backend", "dynamic");
    beresp.set_header("access-control-allow-origin", "*");

    Ok(beresp)
}